(()=>{document.addEventListener("alpine:init",()=>{Alpine.store("jobFilter",{category:"",location:"",employmentType:"",search:"",reset(){this.category="",this.location="",this.employmentType="",this.search=""}}),Alpine.store("notifications",{items:[],add(i,e="info",t=5e3){let s=Date.now();return this.items.push({id:s,message:i,type:e}),t>0&&setTimeout(()=>this.remove(s),t),s},remove(i){this.items=this.items.filter(e=>e.id!==i)},success(i){return this.add(i,"success")},error(i){return this.add(i,"error")}}),Alpine.data("rpFileUpload",(i={})=>({files:[],dragging:!1,error:null,maxFiles:i.maxFiles||5,maxSize:(i.maxSize||10)*1024*1024,allowedTypes:i.allowedTypes||["pdf","doc","docx"],init(){this.$watch("files",e=>{this.$dispatch("files-updated",{files:[...e]})})},handleSelect(e){this.addFiles(e.target.files),e.target.value=""},handleDrop(e){this.dragging=!1,this.addFiles(e.dataTransfer.files)},isValidType(e){let t=e.name.split(".").pop().toLowerCase();return this.allowedTypes.includes(t)},addFiles(e){this.error=null;for(let t of e){if(this.files.length>=this.maxFiles){this.error=i.errorMaxFiles||"Maximal "+this.maxFiles+" Dateien erlaubt";break}if(!this.isValidType(t)){this.error=i.errorInvalidType||"Ung\xFCltiger Dateityp";continue}if(t.size>this.maxSize){this.error=i.errorTooLarge||"Datei zu gro\xDF";continue}this.files.push(t)}},removeFile(e){this.files.splice(e,1)},formatSize(e){return e<1024?e+" B":e<1024*1024?(e/1024).toFixed(1)+" KB":(e/1024/1024).toFixed(1)+" MB"}}))});console.log("Recruiting Playbook Frontend loaded");})();
